(function () {
  if (typeof document === 'undefined') return;

  var input = document.getElementById('homeSearchInput');
  var resultsEl = document.getElementById('homeSearchResults');
  var chipsEl = document.getElementById('homeSearchChips');
  var filtersEl = document.getElementById('homeSearchFilters');
  if (!input || !resultsEl) return;

  var activeFilter = 'all';
  var activeIndex = -1;

  var SEARCH_INDEX = [
    { title: 'Calculadora de sueldo neto', url: '/tools/sueldo-neto.html', section: 'herramienta', terms: 'sueldo neto nomina salario' },
    { title: 'Calculadora de finiquito', url: '/tools/finiquito.html', section: 'herramienta', terms: 'finiquito despido vacaciones' },
    { title: 'Calculadora de indemnizacion por despido', url: '/tools/calculadora-indemnizacion-despido.html', section: 'herramienta', terms: 'indemnizacion despido improcedente objetivo' },
    { title: 'Calculadora del paro', url: '/tools/calculadora-paro.html', section: 'herramienta', terms: 'paro prestacion desempleo sepe' },
    { title: 'Duracion del paro', url: '/tools/duracion-paro.html', section: 'herramienta', terms: 'duracion paro dias cotizados' },
    { title: 'Calculadora de dias cotizados', url: '/tools/calculadora-dias-cotizados.html', section: 'herramienta', terms: 'dias cotizados vida laboral' },
    { title: 'Calculadora de IRPF en nomina', url: '/tools/calculadora-irpf-nomina.html', section: 'herramienta', terms: 'irpf nomina retencion' },
    { title: 'Calculadora de pagas extra', url: '/tools/calculadora-pagas-extra.html', section: 'herramienta', terms: 'pagas extra prorrata' },
    { title: 'Calculadora de jubilacion', url: '/tools/calculadora-jubilacion.html', section: 'herramienta', terms: 'jubilacion pension retiro' },
    { title: 'Calculadora de incapacidad permanente', url: '/tools/calculadora-incapacidad-permanente.html', section: 'herramienta', terms: 'incapacidad permanente total absoluta gran invalidez' },
    { title: 'Calculadora de vacaciones generadas', url: '/tools/calculadora-vacaciones-generadas.html', section: 'herramienta', terms: 'vacaciones generadas pendientes' },
    { title: 'Calculadora de plus de nocturnidad', url: '/tools/calculadora-plus-nocturnidad.html', section: 'herramienta', terms: 'plus nocturnidad noche' },
    { title: 'Hub de autonomos', url: '/autonomos/', section: 'seccion', terms: 'autonomos iva cuota irpf' },
    { title: 'Guia completa del paro', url: '/guia/paro-en-espana-guia-completa.html', section: 'guia', terms: 'guia paro completa sepe' },
    { title: 'Como calcular finiquito en Espana', url: '/guia/como-calcular-finiquito-en-espana.html', section: 'guia', terms: 'guia finiquito despido' },
    { title: 'Como calcular indemnizacion por despido', url: '/guia/como-calcular-indemnizacion-por-despido.html', section: 'guia', terms: 'guia indemnizacion despido' },
    { title: 'Como leer una nomina', url: '/guia/como-leer-una-nomina.html', section: 'guia', terms: 'nomina leer bruto neto' },
    { title: 'Diferencia entre sueldo bruto y neto', url: '/guia/diferencia-entre-sueldo-bruto-y-neto.html', section: 'guia', terms: 'bruto neto salario' },
    { title: 'Gastos deducibles autonomos', url: '/guia/gastos-deducibles-autonomos-iva-irpf.html', section: 'guia', terms: 'autonomos gastos deducibles iva irpf' },
    { title: 'Como solicitar el paro paso a paso', url: '/guia/como-solicitar-el-paro-paso-a-paso.html', section: 'guia', terms: 'solicitar paro sepe pasos' },
    { title: 'Derechos del trabajador 2026', url: '/guia/derechos-del-trabajador-2026.html', section: 'guia', terms: 'derechos trabajador 2026 laboral' },
    { title: 'Cambios laborales 2026', url: '/guia/cambios-laborales-2026.html', section: 'guia', terms: 'cambios laborales 2026 normativa' },
    { title: 'Declarar IRPF 2026', url: '/guia/declarar-irpf-2026.html', section: 'guia', terms: 'declaracion irpf renta 2026' }
  ];

  function normalize(text) {
    return (text || '')
      .toLowerCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .trim();
  }

  function scoreItem(query, item) {
    var q = normalize(query);
    if (!q) return 0;
    var title = normalize(item.title);
    var terms = normalize(item.terms);
    var score = 0;

    if (title === q) score += 120;
    if (title.indexOf(q) !== -1) score += 70;
    if (terms.indexOf(q) !== -1) score += 35;

    var words = q.split(/\s+/);
    for (var i = 0; i < words.length; i += 1) {
      if (title.indexOf(words[i]) !== -1) score += 16;
      else if (terms.indexOf(words[i]) !== -1) score += 8;
    }

    return score;
  }

  function renderResults(query) {
    var q = normalize(query);
    activeIndex = -1;

    if (!q) {
      resultsEl.innerHTML = '';
      return;
    }

    var pool = activeFilter === 'all'
      ? SEARCH_INDEX
      : SEARCH_INDEX.filter(function (item) {
          return item.section === activeFilter || (activeFilter === 'herramienta' && item.section === 'seccion');
        });

    var ranked = pool
      .map(function (item) {
        return { item: item, score: scoreItem(q, item) };
      })
      .filter(function (row) { return row.score > 0; })
      .sort(function (a, b) { return b.score - a.score; })
      .slice(0, 8);

    if (ranked.length === 0) {
      resultsEl.innerHTML = '<div class="search-empty">No encuentro resultados para &ldquo;' + query.replace(/</g, '&lt;') + '&rdquo;. Prueba con: paro, finiquito, IRPF, nómina o autónomos.</div>';
      return;
    }

    resultsEl.innerHTML = ranked.map(function (row) {
      return '<a class="search-result-link" href="' + row.item.url + '">' +
        '<span class="search-result-title">' + row.item.title + '</span>' +
        '<span class="search-result-meta">' + row.item.section + '</span>' +
      '</a>';
    }).join('');
  }

  function getResultLinks() {
    return Array.prototype.slice.call(resultsEl.querySelectorAll('a.search-result-link'));
  }

  function activateLink(index) {
    var links = getResultLinks();
    links.forEach(function (link, i) {
      link.classList.toggle('is-active', i === index);
    });
    activeIndex = index;
    if (links[index]) links[index].focus();
  }

  input.addEventListener('input', function () {
    renderResults(input.value);
    if (typeof gtag === 'function' && normalize(input.value).length >= 3) {
      gtag('event', 'home_search_input', { event_category: 'engagement', event_label: normalize(input.value) });
    }
  });

  input.addEventListener('keydown', function (e) {
    var links = getResultLinks();
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      activateLink(Math.min(activeIndex + 1, links.length - 1));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (activeIndex <= 0) { activeIndex = -1; input.focus(); } else { activateLink(activeIndex - 1); }
    } else if (e.key === 'Escape') {
      input.value = ''; resultsEl.innerHTML = ''; activeIndex = -1;
    }
  });

  resultsEl.addEventListener('keydown', function (e) {
    var links = getResultLinks();
    var focused = document.activeElement;
    var idx = links.indexOf(focused);
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      if (idx < links.length - 1) activateLink(idx + 1);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (idx <= 0) { activeIndex = -1; input.focus(); } else { activateLink(idx - 1); }
    } else if (e.key === 'Escape') {
      input.value = ''; resultsEl.innerHTML = ''; activeIndex = -1; input.focus();
    }
  });

  resultsEl.addEventListener('click', function (event) {
    var link = event.target.closest('a.search-result-link');
    if (!link) return;
    if (typeof gtag === 'function') {
      gtag('event', 'home_search_click', { event_category: 'engagement', event_label: link.getAttribute('href') || '' });
    }
  });

  if (filtersEl) {
    filtersEl.addEventListener('click', function (event) {
      var btn = event.target.closest('button.search-filter');
      if (!btn) return;
      activeFilter = btn.getAttribute('data-filter') || 'all';
      Array.prototype.forEach.call(filtersEl.querySelectorAll('.search-filter'), function (b) {
        b.classList.toggle('active', b === btn);
      });
      renderResults(input.value);
    });
  }

  if (chipsEl) {
    chipsEl.addEventListener('click', function (event) {
      var chip = event.target.closest('button.search-chip');
      if (!chip) return;
      input.value = chip.getAttribute('data-query') || '';
      renderResults(input.value);
      input.focus();
    });
  }
})();
